results.raw_sql:
SELECT p.productCode, p.productName, SUM(od.quantityOrdered * od.priceEach) AS salesAmount
FROM orders o JOIN orderdetails od ON o.orderNumber = od.orderNumber
WHERE o.productLine = 'Ships' GROUP BY p.productCode, p.productName ORDER BY salesAmount DESC LIMIT 5;

